export class Common{constructor(t){this.padding=null,this.footerHeight=null,this.init()}async init(){document.querySelector("section").style.paddingBottom="0",this.padding=window.innerHeight-document.querySelector("section").clientHeight,this.footerHeight=document.querySelector("footer").clientHeight,this.padding<40?document.querySelector("section").style.paddingBottom="40px":document.querySelector("section").style.paddingBottom=this.padding-this.footerHeight+"px"}}